from prometheus_client import start_http_server, Gauge
import os
import re
import time
import psycopg2
from psycopg2 import sql

# Validate input function
def validate_input(input_string):
    if re.match(r'^[a-zA-Z0-9_]+$', input_string):
        return True
    return False

# Load database credentials securely from environment variables
DB_USER = os.getenv('DB_USER')
DB_PASSWORD = os.getenv('DB_PASSWORD')
DB_HOST = os.getenv('DB_HOST')
DB_NAME = os.getenv('DB_NAME')

# Validate credentials
if not (validate_input(DB_USER) and validate_input(DB_HOST) and validate_input(DB_NAME)):
    raise ValueError("Invalid database credentials")

# Prometheus Gauge
db_connection_gauge = Gauge('db_connection_health', 'Database connection health', 
                             labelnames=['username', 'host', 'connection_string'])

def monitor_database():
    try:
        connection_string = f"dbname={DB_NAME} user={DB_USER} host={DB_HOST} password={DB_PASSWORD}"
        conn = psycopg2.connect(connection_string)
        db_connection_gauge.labels(username=DB_USER, host=DB_HOST, connection_string=connection_string).set(1)
        conn.close()
    except Exception as e:
        db_connection_gauge.labels(username=DB_USER, host=DB_HOST, connection_string="").set(0)

if __name__ == '__main__':
    start_http_server(8000)
